BEGIN
 FUNCTION countWords(String sentence)
 Map<String, Integer> wordCount = NEW HashMap<>()
 String[] words = sentence.split("\\s+")

 FOR EACH word IN words
 // merge(key, value, remappingFunction)
 // If key absent: insert value
 // If key present: apply remappingFunction to combine
 wordCount.merge(word.toLowerCase(), 1, Integer::sum)
 END FOR

 RETURN wordCount
 END FUNCTION

 // Alternative using computeIfAbsent for complex computation
 FUNCTION countWithComputeIfAbsent(Map<String, Set<String>> index, String word)
 // Only compute if word not present (simulates lazy loading)
 index.computeIfAbsent(word.toLowerCase(), 
 w -> NEW HashSet<>()).add(word)
 END FUNCTION

 // Usage
 Map<String, Integer> counts = countWords("hello world hello Java world")
 PRINT counts // {hello=2, world=2, java=1}
END
